conditions.leftValue:
={{
  (() => {
    const findValue = (obj, matcher) => {
      if (!obj || typeof obj !== 'object') return undefined;

      for (const [key, value] of Object.entries(obj)) {
        if (matcher(key) && typeof value !== 'object') {
          return value;
        }

        const nested = findValue(value, matcher);
        if (nested !== undefined) return nested;
      }

      return undefined;
    };

    const state = $json.state ?? {};

    return (
      findValue(state, key => key.toLowerCase().includes('bant')) ??
      findValue(state, key => key.toLowerCase().includes('score'))
    );
  })()
}}

